    // print original tree preorder
    cout << "Binary Tree Preorder: ";
    printPreorder(root);
    cout << endl;

    // flatten the tree
    sol.flatten(root);

    // print flattened tree via right pointers
    cout << "Binary Tree After Flatten: ";
    printFlattenTree(root);
    cout << endl;

    // finish program
    return 0;
